import streamlit as st
import json

st.set_page_config(page_title="Code Review Agent", layout="wide")

st.title("🔍 AI Code Review Agent")
st.write("Analyze your code for bugs, security issues, and improvements.")

# ----------- ANALYZER FUNCTION -----------
def analyze_code(code):
    issues = []

    # 🔴 Hardcoded password
    if "password =" in code.lower():
        issues.append(("High", "Hardcoded password detected"))

    # 🔴 SQL Injection risk
    if "select" in code.lower() and "+" in code:
        issues.append(("High", "Possible SQL Injection vulnerability"))

    # 🟡 User input without validation
    if "input(" in code:
        issues.append(("Medium", "User input without validation"))

    # 🟡 Use of eval()
    if "eval(" in code:
        issues.append(("High", "Use of eval() is dangerous"))

    # 🟢 No issues
    if not issues:
        issues.append(("Low", "No major issues found"))

    return issues


# ----------- SCORING FUNCTION -----------
def calculate_score(issues):
    score = 10

    for level, _ in issues:
        if level == "High":
            score -= 2
        elif level == "Medium":
            score -= 1

    return max(score, 1)


# ----------- MEMORY FUNCTION -----------
def save_review(code, issues, score):
    data = {
        "code": code,
        "issues": issues,
        "score": score
    }

    try:
        with open("reviews.json", "r") as f:
            reviews = json.load(f)
    except:
        reviews = []

    reviews.append(data)

    with open("reviews.json", "w") as f:
        json.dump(reviews, f, indent=4)


# ----------- UI INPUT -----------
code = st.text_area("📌 Paste your code here:", height=200)

# ----------- ANALYZE BUTTON -----------
if st.button("🚀 Analyze Code"):
    if code.strip() == "":
        st.warning("Please enter code!")
    else:
        st.subheader("🧠 Analysis Results")

        issues = analyze_code(code)

        for level, msg in issues:
            if level == "High":
                st.error(f"{level}: {msg}")
            elif level == "Medium":
                st.warning(f"{level}: {msg}")
            else:
                st.success(f"{level}: {msg}")

        # Score
        score = calculate_score(issues)
        st.subheader(f"📊 Code Quality Score: {score}/10")

        # Suggestions
        st.subheader("💡 Suggestions")
        for level, msg in issues:
            if "password" in msg.lower():
                st.write("👉 Use environment variables instead of hardcoding passwords.")
            elif "sql" in msg.lower():
                st.write("👉 Use parameterized queries to prevent SQL injection.")
            elif "input" in msg.lower():
                st.write("👉 Validate and sanitize user inputs.")
            elif "eval" in msg.lower():
                st.write("👉 Avoid using eval(); use safer alternatives.")

        # Save memory
        save_review(code, issues, score)
        st.success("✅ Review saved successfully!")


# ----------- SHOW HISTORY -----------
if st.button("📂 Show Past Reviews"):
    try:
        with open("reviews.json", "r") as f:
            reviews = json.load(f)

        st.subheader("📜 Past Reviews")
        for r in reviews:
            st.write(r)
    except:
        st.info("No past reviews found.")

